void FusionNode<Msg3D, Msg2D, ExportObj>::camera_info_callback(
  const sensor_msgs::msg::CameraInfo::ConstSharedPtr input_camera_info_msg,
  const std::size_t rois_id)
{
  if (rois_id >= det2d_status_list_.size()) {
    throw std::out_of_range("rois_id " + std::to_string(rois_id) + " is out of range.");
  }

  // Create the CameraProjection only when the camera info arrives for the first time.
  // This assume the camera info does not change while the node is running
  auto & det2d_status = det2d_status_list_.at(rois_id);
  if (det2d_status.camera_projector_ptr == nullptr && check_camera_info(*input_camera_info_msg)) {
    std::atomic<bool> initializing{true};
    std::thread([this, &initializing, rois_id]() {
      rclcpp::Rate rate(1.0);  // 1 Hz
      while (rclcpp::ok() && initializing.load()) {
        RCLCPP_WARN(
          this->get_logger(), "Still initializing camera projector for ROI %zu... please wait...",
          rois_id);
        rate.sleep();
      }
    }).detach();

    det2d_status.camera_projector_ptr = std::make_unique<CameraProjection>(
      *input_camera_info_msg, approx_grid_cell_w_size_, approx_grid_cell_h_size_,
      det2d_status.project_to_unrectified_image, det2d_status.approximate_camera_projection);
    det2d_status.camera_projector_ptr->initialize();

    // Mark as finished
    initializing = false;
    RCLCPP_INFO(
      this->get_logger(), "Camera projector initialization for ROI %zu finished.", rois_id);

    std::unique_lock<std::mutex> fusion_collectors_lock(fusion_collectors_mutex_);
    for (auto & collector : fusion_collectors_) {
      collector->add_camera_projection(rois_id, det2d_status.camera_projector_ptr);
    }
  }
}

bool check_camera_info(const sensor_msgs::msg::CameraInfo & camera_info)
{
  const bool is_supported_model =
    (camera_info.distortion_model == sensor_msgs::distortion_models::PLUMB_BOB ||
     camera_info.distortion_model == sensor_msgs::distortion_models::RATIONAL_POLYNOMIAL);
  if (!is_supported_model) {
    RCLCPP_ERROR_STREAM(
      rclcpp::get_logger("image_projection_based_fusion"),
      "check_camera_info: Unsupported distortion model: " << camera_info.distortion_model);
    return false;
  }
  const bool is_supported_distortion_param =
    (camera_info.d.size() == 5 || camera_info.d.size() == 8);
  if (!is_supported_distortion_param) {
    RCLCPP_ERROR_STREAM(
      rclcpp::get_logger("image_projection_based_fusion"),
      "check_camera_info: Unsupported distortion coefficients size: " << camera_info.d.size());
    return false;
  }
  return true;
}

void FusionCollector<Msg3D, Msg2D, ExportObj>::add_camera_projection(
  std::size_t rois_id, std::shared_ptr<CameraProjection> camera_projector_ptr)
{
  std::lock_guard<std::mutex> lock(fusion_mutex_);
  det2d_status_list_[rois_id].camera_projector_ptr = camera_projector_ptr;
}
